def test_single_pin_change_succeeds(fresh_card, auth_headers):
    card_id = fresh_card["id"]
    payload = {"pin": "1234"}
    resp = <api_client>.patch(
        f"/cards/{card_id}/pin",
        json=payload,
        headers=auth_headers,
    )
    assert resp.status_code in (200, 204), (
        f"Expected 200/204, got {resp.status_code}: {resp.text}"
    )

def test_fifth_pin_change_is_allowed(fresh_card, auth_headers):
    card_id = fresh_card["id"]
    pins = ["1111", "2222", "3333", "4444"]
    for pin in pins:
        r = <api_client>.patch(
            f"/cards/{card_id}/pin",
            json={"pin": pin},
            headers=auth_headers,
        )
        assert r.status_code in (200, 204), (
            f"Pre-condition setup failed on change {pin}: {r.status_code}"
        )
    resp = <api_client>.patch(
        f"/cards/{card_id}/pin",
        json={"pin": "5555"},
        headers=auth_headers,
    )
    assert resp.status_code in (200, 204), (
        f"5th change should succeed; got {resp.status_code}: {resp.text}"
    )

def test_sixth_pin_change_returns_429(fresh_card, auth_headers):
    card_id = fresh_card["id"]
    pins = ["1111", "2222", "3333", "4444", "5555"]
    for pin in pins:
        r = <api_client>.patch(
            f"/cards/{card_id}/pin",
            json={"pin": pin},
            headers=auth_headers,
        )
        assert r.status_code in (200, 204), (
            f"Setup failed on change {pin}: {r.status_code}"
        )
    resp = <api_client>.patch(
        f"/cards/{card_id}/pin",
        json={"pin": "6666"},
        headers=auth_headers,
    )
    assert resp.status_code == 429, (
        f"Expected 429, got {resp.status_code}: {resp.text}"
    )

def test_pin_change_on_unowned_card_is_forbidden(
    owner_card, attacker_auth_headers
):
    card_id = owner_card["id"]
    resp = <api_client>.patch(
        f"/cards/{card_id}/pin",
        json={"pin": "9999"},
        headers=attacker_auth_headers,
    )
    assert resp.status_code in (403, 404), (
        f"Expected 403 or 404 for unowned card, got {resp.status_code}: {resp.text}"
    )

def test_state_transition_under_to_at_to_over_limit(
    fresh_card, auth_headers
):
    card_id = fresh_card["id"]
    for i, pin in enumerate(["1111","2222","3333","4444","5555"], start=1):
        r = <api_client>.patch(
            f"/cards/{card_id}/pin",
            json={"pin": pin},
            headers=auth_headers,
        )
        assert r.status_code in (200, 204), (
            f"Change {i} should succeed; got {r.status_code}"
        )
    over = <api_client>.patch(
        f"/cards/{card_id}/pin",
        json={"pin": "6666"},
        headers=auth_headers,
    )
    assert over.status_code == 429, (
        f"6th change must be blocked; got {over.status_code}: {over.text}"
    )
